use std::collections::HashMap;
use std::fmt::Write;

#[derive(Eq, Hash, PartialEq)]
struct CacheKey(String);
struct CachedValue(Vec<u8>);

fn process_request<'a>(input: &'a str, data: &'a HashMap<CacheKey, CachedValue>) -> String {
    let mut output = String::new();
    writeln!(output, "Processing request for input: {}", input).unwrap();

    if let Some(key) = data.get(&CacheKey(format!("{}", input))) {
        write!(output, "Found cached result using key: {}", input).unwrap();
    } else {
        write!(output, "No cache found for input: {}", input).unwrap();
    }

    output
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut shared_data = HashMap::new();
    shared_data.insert(CacheKey("initial_asset".to_string()), CachedValue(b"binary_content".to_vec()));

    let input1 = "initial_asset";
    let result1 = process_request(input1, &shared_data);
    println!("n--- Result 1 ---n{}", result1);

    let input2 = "new_component";
    let result2 = process_request(input2, &shared_data);
    println!("n--- Result 2 ---n{}", result2);

    Ok(())
}

use std::collections::VecDeque;

struct DataStream {
    buffer: VecDeque<f64>,
}

impl DataStream {
    fn new() -> Self {
        DataStream { 
            buffer: VecDeque::new()
        }
    }

    fn add_reading(&mut self, reading: f64) {
        self.buffer.push_back(reading);
    }

    fn calculate_mean<'a>(data: &'a [f64]) -> Option<f64> {
        if data.is_empty() {
            return None;
        }
        let sum: f64 = data.iter().sum();
        Some(sum / (data.len() as f64))
    }
}

use std::collections::HashMap;
use std::thread;
use std::time::Duration;

#[derive(Debug, Clone)]
struct SystemStat {
    cpu_usage: f32,
    memory_used_gb: f32,
}

fn collect_stats() -> SystemStat {
    SystemStat {
        cpu_usage: 45.5,
        memory_used_gb: 16.2,
    }
}

// This function simulates capturing a reading and needs to handle the lifetime of that data.
fn process_and_store(current_stat: SystemStat) -> HashMap<String, SystemStat> {
    let mut storage = HashMap::new();
    storage.insert("cpu".to_string(), current_stat);
    storage
}

fn main() {
    let mut history: HashMap<String, SystemStat> = HashMap::new();
    for i in 0..3 {
        thread::sleep(Duration::from_millis(100));
        let new_reading = collect_stats();
        println!("n--- Cycle {} ---", i + 1);
        let updated_history = process_and_store(new_reading);
        for (key, stat) in &updated_history {
            if let Some(old_stat) = history.get(key) {
                println!("\"{}\": Old CPU: {:.1}%, New CPU: {:.1}%", key, old_stat.cpu_usage, stat.cpu_usage);
            }
            history.insert(key.to_string(), stat.clone());
        }
    }
    println!("nFinished monitoring cycles.");
}

use std::collections::HashMap;

struct GameState {
    settings: HashMap<String, String>,
}

fn process_captured_data(state: &GameState) -> String {
    let mut results = Vec::new();
    for (key, value) in state.settings.iter() {
        results.push(format!("{}: {}", key, value));
    }
    results.join(", ")
}

fn main() {
    let global_config = GameState {
        settings: HashMap::from([("map_name".to_string(), "Aoki".to_string()), ("difficulty".to_string(), "Hard".to_string())]),
    };

    let process_closure = move |state: &GameState| -> String {
        process_captured_data(state)
    };

    let final_output = process_closure(&global_config);
    println!("Successfully processed state: {}", final_output);
}

use std::collections::HashMap;
use serde::{Serialize, Deserialize};

#[derive(Debug, Clone, Serialize, Deserialize)]
struct BenchmarkData {
    name: String,
    value: f64,
}

fn process_data(mut data: Vec<BenchmarkData>) -> HashMap<String, f64> {
    let mut results = HashMap::new();
    for item in data.iter() {
        results.insert(item.name.clone(), item.value);
    }
    results
}

fn main() {
    let initial_data = vec![
        BenchmarkData { name: "json".to_string(), value: 0.95 },
        BenchmarkData { name: "yaml".to_string(), value: 0.88 },
        BenchmarkData { name: "toml".to_string(), value: 0.91 },
    ];

    let processing_closure = |data_slice: &[BenchmarkData]| -> HashMap<String, f64> {
        let mut local_results = HashMap::new();
        for item in data_slice.iter() {
            local_results.insert(item.name.clone(), item.value);
        }
        local_results
    };

    let results = processing_closure(&initial_data);

    println!("Benchmark Comparison Results:");
    for (key, val) in &results {
        println!("{}: {:.2}", key, val);
    }
}
